prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "2d225c9ff86b443c9f6bc6cfe687afbc" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org bbo:name ?orgName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?origId ?normId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:originalId ?origId . }
  OPTIONAL { ?model tai:normalizedId ?normId . }
  FILTER(CONTAINS(LCASE(STR(?origId)), "2d225c9ff86b443c9f6bc6cfe687afbc") || 
         CONTAINS(LCASE(STR(?normId)), "2d225c9ff86b443c9f6bc6cfe687afbc") ||
         CONTAINS(LCASE(STR(?model)), "2d225c9ff86b443c9f6bc6cfe687afbc"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?elem ?type ?elemName ?gatewayDir WHERE {
  ?elem tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_a91555f6_d70d_4c6b_b0ad_d70ef853da6e> .
  ?elem a ?type .
  OPTIONAL { ?elem bbo:name ?elemName . }
  OPTIONAL { ?elem bboExt:gatewayDirection ?gatewayDir . }
  FILTER(?type IN (bbo:SequenceFlow, bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
}
LIMIT 50

